module top_module(
output reg [3:0] n_ascci,
input clk,
input add_ascci,
input reset_ascci
 );reg [3:0] obf_temp;
always @(posedge clk) begin
		if (reset_ascci == 1)	obf_temp <= 4'b0000;
		else if (add_ascci == 1) obf_temp <= obf_temp+1;
			else obf_temp<=obf_temp;
		end	
always @(obf_temp) begin
		n_ascci <= obf_temp;
	end
endmodule
